/*==============================================================*/
/* Table: CDTCAT                                                */
/*==============================================================*/
CREATE TABLE CDTCAT
(
    ID_CDTCAT_CODE       INT NOT NULL AUTO_INCREMENT,
    XID_CDTTIP_ID        INT,
    CDTCAT_NAME          VARCHAR(64) NOT NULL,
    CDTCAT_VALID_FROM    TIMESTAMP,
    CDTCAT_VALID_TO      TIMESTAMP NULL,
    CDTCAT_CREATED_BY    VARCHAR(16),
    CDTCAT_UPDATED_BY    VARCHAR(16),
    CDTCAT_CREATED_AT    TIMESTAMP,
    CDTCAT_UPDATED_AT    TIMESTAMP,
    PRIMARY KEY (ID_CDTCAT_CODE)
);

ALTER TABLE CDTCAT COMMENT 'CATALOGO BODEGA';

/*==============================================================*/
/* Table: CDTTIP                                                */
/*==============================================================*/
CREATE TABLE CDTTIP
(
    ID_CDTTIP_ID         INT NOT NULL AUTO_INCREMENT,
    CDTTIP_NAME          VARCHAR(8) NOT NULL,
    CDTTIP_DESCRIPTION   VARCHAR(64) NOT NULL,
    CDTTIP_VALID_FROM    TIMESTAMP,
    CDTTIP_VALID_TO      TIMESTAMP NULL,
    CDTTIP_CREATED_BY    VARCHAR(16),
    CDTTIP_UPDATED_BY    VARCHAR(16),
    CDTTIP_CREATED_AT    TIMESTAMP,
    CDTTIP_UPDATED_AT    TIMESTAMP,
    PRIMARY KEY (ID_CDTTIP_ID)
);

ALTER TABLE CDTTIP COMMENT 'TIPO CATALOGO BODEGA';

ALTER TABLE CDTCAT ADD CONSTRAINT XID_CDTCAT_CODE_XID_CDTTIP_CODE FOREIGN KEY (XID_CDTTIP_ID)
    REFERENCES CDTTIP (ID_CDTTIP_ID) ON DELETE RESTRICT ON UPDATE RESTRICT;



